<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    call </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SetUnitLife</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(u, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 恢复单位生命值</span></span>
